import abc

class PaymentProcessor(abc.ABC):
    @abc.abstractmethod
    def process_payment(self, amount: float):
        pass

class Logger(abc.ABC):
    @abc.abstractmethod
    def log_message(self, message: str):
        pass

class MyService(PaymentProcessor, Logger):
    def __init__(self, service_id: str):
        self._service_id = service_id

    def process_payment(self, amount: float):
        print(f"Service '{self._service_id}': Processing payment of ${amount:.2f}")
        self.log_message(f"Payment of ${amount:.2f} processed successfully.")

    def log_message(self, message: str):
        print(f"Service '{self._service_id}' LOG: {message}")

if __name__ == "__main__":
    service_instance = MyService("OrderService-001")
    service_instance.process_payment(250.75)
    service_instance.log_message("Service initialized and ready.")
